class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = Player("Black")

    def switch_player(self):
        if self.current_player.color == "Black":
            self.current_player = Player("White")
        else:
            self.current_player = Player("Black")

    def make_move(self, from_pos, to_pos):
        # Convert positions to indices
        from_row, from_col = ord(from_pos[0]) - ord('a'), int(from_pos[1])
        to_row, to_col = ord(to_pos[0]) - ord('a'), int(to_pos[1])

        # Move the piece
        if self.board.board[from_row][from_col]:
            self.board.board[to_row][to_col] = self.board.board[from_row][from_col]
            self.board.board[from_row][from_col] = None

            # Check for capture
            if abs(from_row - to_row) == 2 and abs(from_col - to_col) == 2:
                mid_row, mid_col = (from_row + to_row) // 2, (from_col + to_col) // 2
                captured_piece = self.board.board[mid_row][mid_col]
                if captured_piece:
                    self.board.board[mid_row][mid_col] = None

            # Check for kinging
